// Get data from previous nodes
const salesforceRows = $('Salesforce_Data').all().map(item => item.json);
const annualReport = $('Annual Data').first().json;

const reportedValue = parseInt(annualReport.Reported_Value);
const periodStart = annualReport.Reporting_Period_Start;
const periodEnd = annualReport.Reporting_Period_End;

const anomalies = [];

// Step 1 - Filter only Completed records
const completedRecords = salesforceRows.filter(r => r.Status === 'Completed');

// Step 2 - Flag and filter out-of-range delivery dates
const inRangeRecords = [];
for (const r of completedRecords) {
  const delivery = r.Delivery_Date || '';
  if (!delivery || delivery < periodStart || delivery > periodEnd) {
    anomalies.push(`${r.Record_ID} (${r.Family_Name}): Delivery date '${delivery}' outside reporting period`);
  } else {
    inRangeRecords.push(r);
  }
}

// Step 3 - Flag non-completed records
for (const r of salesforceRows) {
  if (r.Status !== 'Completed') {
    anomalies.push(`${r.Record_ID} (${r.Family_Name}): Status is '${r.Status}' - excluded`);
  }
}

// Step 4 - Deduplicate by Family_ID
const familyMap = {};
for (const r of inRangeRecords) {
  const fid = r.Family_ID;
  if (!familyMap[fid]) {
    familyMap[fid] = r;
  } else {
    anomalies.push(`${r.Record_ID} (${r.Family_Name}): Duplicate Family_ID ${fid} - counted once only`);
  }
}

const uniqueFamilyCount = Object.keys(familyMap).length;
const gap = reportedValue - uniqueFamilyCount;

return [{
  json: {
    raw_salesforce_count: salesforceRows.length,
    after_status_filter: completedRecords.length,
    after_date_filter: inRangeRecords.length,
    unique_families: uniqueFamilyCount,
    annual_report_value: reportedValue,
    gap: gap,
    reporting_period: `${periodStart} to ${periodEnd}`,
    anomalies: anomalies,
    anomaly_count: anomalies.length
  }
}];

